  p_help_pplns_title: "PPLNS (Pay Per Last N Shares)",
  p_help_pplns_desc: "PPLNS\ub294 \ube14\ub85d \ubc1c\uacac\uc5d0 \ub300\ud55c \uae30\uc5ec\ub3c4\uc5d0 \ub530\ub77c \ub9c8\uc774\ub108\uc5d0\uac8c \ubcf4\uc0c1\uc744 \uc81c\uacf5\ud569\ub2c8\ub2e4. \ud480\uc774 \ube14\ub85d\uc744 \ucc3e\uc73c\uba74 \uc2a4\ucf54\uc5b4\ub9c1 \ucc3d\uc5d0\uc11c \uc720\ud6a8\ud55c \uc250\uc5b4\ub97c \uc81c\ucd9c\ud55c \ubaa8\ub4e0 \ub9c8\uc774\ub108\uc5d0\uac8c \ube44\ub840\ud558\uc5ec \ubcf4\uc0c1\uc774 \ubd84\ubc30\ub429\ub2c8\ub2e4.",
