  p_help_pplns_luck: "<strong>\uc6b4 \uacf5\uc720:</strong> \ubd88\uc6b4\uc740 \ubaa8\ub4e0 \ub9c8\uc774\ub108\uc5d0\uac8c \ubd84\uc0b0",

  p_help_solo_title: "\uc194\ub85c \ub9c8\uc774\ub2dd",
  p_help_solo_desc: "\uc194\ub85c \ubaa8\ub4dc\uc5d0\uc11c\ub294 \ud480\uc758 \uc778\ud504\ub77c\ub97c \uc0ac\uc6a9\ud558\uc5ec \ub3c5\ub9bd\uc801\uc73c\ub85c \ub9c8\uc774\ub2dd\ud569\ub2c8\ub2e4. \ube14\ub85d\uc744 \ucc3e\uc73c\uba74 \uc804\uc561 \ubcf4\uc0c1\uc744 \ubcf4\uc720\ud569\ub2c8\ub2e4(0.5% \uc218\uc218\ub8cc \uc81c\uc678). \ub2e4\ub978 \uc0ac\ub78c\uc774 \ube14\ub85d\uc744 \ucc3e\uc73c\uba74 \uc544\ubb34\uac83\ub3c4 \ubc1b\uc9c0 \ubabb\ud569\ub2c8\ub2e4.",
  p_help_solo_max: "<strong>\ucd5c\ub300 \ubcf4\uc0c1:</strong> \ucc3e\uc740 \ube14\ub85d\ub2f9 49.75 BCH2 \ubcf4\uc720",
  p_help_solo_high: "<strong>\ub192\uc740 \ubcc0\ub3d9\uc131:</strong> \ube14\ub85d\uc744 \ucc3e\uc9c0 \ubabb\ud558\ub294 \uae34 \uae30\uac04\uc774 \uc788\uc744 \uc218 \uc788\uc74c",
  p_help_solo_rec: "<strong>\ucd94\ucc9c \ub300\uc0c1:</strong> \uc0c1\ub2f9\ud55c \ud574\uc2dc\ub808\uc774\ud2b8\ub97c \uac00\uc9c4 \ub9c8\uc774\ub108 (\ub124\ud2b8\uc6cc\ud06c\uc758 >10%)",

  p_help_cooldown_title: "\ubaa8\ub4dc \uc804\ud658 \ub300\uae30 \uc2dc\uac04",
  p_help_cooldown_desc: "\uc545\uc6a9\uc744 \ubc29\uc9c0\ud558\uae30 \uc704\ud574 PPLNS\uc640 \uc194\ub85c \ubaa8\ub4dc \uac04 \uc804\ud658 \uc2dc \ub300\uae30 \uc2dc\uac04\uc774 \uc788\uc2b5\ub2c8\ub2e4. \uc774\ub294 PPLNS \ud480\uc5d0\uc11c \uacf5\uc815\ud55c \uc250\uc5b4 \ubd84\ubc30\ub97c \ubcf4\uc7a5\ud569\ub2c8\ub2e4.",

  p_help_payouts_title: "\uc9c0\ubd88",
  p_help_payouts_how_title: "\uc9c0\ubd88 \ubc29\ubc95",
  p_help_payouts_how_desc: "Forge Pool\uc740 \uc124\uc815\ub41c BCH2 \uc9c0\uac11 \uc8fc\uc18c\ub85c \uc790\ub3d9\uc73c\ub85c \uc9c0\ubd88\uc744 \ubcf4\ub0c5\ub2c8\ub2e4. \ud504\ub85c\uc138\uc2a4\ub294 \ub2e4\uc74c\uacfc \uac19\uc2b5\ub2c8\ub2e4:",
  p_help_payouts_step1: "<strong>\ube14\ub85d \ubc1c\uacac:</strong> \ud480\uc774 \ube14\ub85d\uc744 \ucc3e\uc73c\uba74 BCH2 \ub124\ud2b8\uc6cc\ud06c\uc5d0 \ube0c\ub85c\ub4dc\ucea0\uc2a4\ud2b8\ub429\ub2c8\ub2e4.",
  p_help_payouts_step2: "<strong>\ud655\uc778 \uae30\uac04:</strong> \ucf54\uc778\ubca0\uc774\uc2a4 \ubcf4\uc0c1\uc744 \uc0ac\uc6a9\ud558\uae30 \uc804\uc5d0 \ube14\ub85d\uc740 <strong>100\ud68c \ud655\uc778</strong>\uc744 \ubc1b\uc544\uc57c \ud569\ub2c8\ub2e4. \ud604\uc7ac \ube14\ub85d \uc2dc\uac04\uc73c\ub85c \uc57d 100\ube14\ub85d(~16-17\uc2dc\uac04)\uc774 \uc18c\uc694\ub429\ub2c8\ub2e4.",
  p_help_payouts_step3: "<strong>\uc9c0\ubd88 \ucc98\ub9ac:</strong> \uc131\uc219\ub418\uba74 \uc9c0\ubd88\uc774 \uc790\ub3d9\uc73c\ub85c \ub9c8\uc774\ub108 \uc8fc\uc18c\ub85c \uc804\uc1a1\ub429\ub2c8\ub2e4.",
  p_help_payouts_step4: "<strong>\uc628\uccb4\uc778 \ud655\uc778:</strong> \ud2b8\ub79c\uc7ad\uc158\uc774 \ud655\uc778\ub418\uba74 \uc9c0\ubd88\uc774 \uc9c0\uac11\uc5d0 \ud45c\uc2dc\ub429\ub2c8\ub2e4.",

  p_help_why100_title: "\uc65c 100\ud68c \ud655\uc778\uc778\uac00\uc694?",
  p_help_why100_desc: "BCH2(\ube44\ud2b8\ucf54\uc778\uacfc \ub9c8\ucc2c\uac00\uc9c0\ub85c)\ub294 \ucf54\uc778\ubca0\uc774\uc2a4 \ud2b8\ub79c\uc7ad\uc158\uc774 \uc0ac\uc6a9 \uac00\ub2a5\ud558\uae30 \uc804\uc5d0 100\ube14\ub85d\uc758 \uc131\uc219\uc744 \uc694\uad6c\ud569\ub2c8\ub2e4. \uc774\ub294 \ube14\ub85d\uc744 \uace0\uc544\ub85c \ub9cc\ub4e4 \uc218 \uc788\ub294 \ube14\ub85d\uccb4\uc778 \uc7ac\uc870\uc9c1\uc73c\ub85c\ubd80\ud130 \ubcf4\ud638\ud569\ub2c8\ub2e4.",

  p_help_pplns_calc_title: "PPLNS \uc9c0\ubd88 \uacc4\uc0b0",
  p_help_pplns_calc_desc: "\uac01 \ube14\ub85d \ubcf4\uc0c1\uc758 \uadc0\ud558\uc758 \ubab6\uc740 \ud480 \ucd1d \uc250\uc5b4\uc5d0 \ub300\ud55c \uae30\uc5ec\ub3c4\ub97c \uae30\ubc18\uc73c\ub85c \uacc4\uc0b0\ub429\ub2c8\ub2e4:",
  p_help_pplns_example: "\uc608\ub97c \ub4e4\uc5b4, \ud480 \uc250\uc5b4\uc758 10%\ub97c \uae30\uc5ec\ud558\uace0 \ud480\uc774 \ube14\ub85d\uc744 \ucc3e\uc740 \uacbd\uc6b0:",

  p_help_min_payout_title: "\ucd5c\uc18c \uc9c0\ubd88\uc561",
  p_help_min_payout_desc: "\ucd5c\uc18c \uc9c0\ubd88 \uc784\uacc4\uac12\uc740 <strong>0.01 BCH2</strong>\uc785\ub2c8\ub2e4. \ub354 \uc801\uc740 \uae08\uc561\uc740 \uc774 \uc784\uacc4\uac12\uc5d0 \ub3c4\ub2ec\ud560 \ub54c\uae4c\uc9c0 \ub204\uc801\ub429\ub2c8\ub2e4.",

